4: define('forum/topic/move-post', [
5: 	'components', 'postSelect', 'translator', 'alerts', 'api',
6: ], function (components, postSelect, translator, alerts, api) {
7: 	const MovePost = {};
8: 
9: 	let moveModal;
10: 	let moveCommit;
11: 	let fromTid;
12: 
13: 	MovePost.init = function (postEl) {
14: 		if (moveModal) {
15: 			return;
16: 		}
17: 		fromTid = ajaxify.data.tid;
18: 		app.parseAndTranslate('modals/move-post', {}, function (html) {
19: 			moveModal = html;
20: 
21: 			moveCommit = moveModal.find('#move_posts_confirm');
22: 
23: 			$('body').append(moveModal);
24: 
25: 			moveModal.find('#move_posts_cancel').on('click', closeMoveModal);
26: 			moveModal.find('#topicId').on('keyup', utils.debounce(checkMoveButtonEnable, 200));
27: 			postSelect.init(onPostToggled);
28: 			showPostsSelected();
29: 
30: 			if (postEl) {
31: 				postSelect.togglePostSelection(postEl, postEl.attr('data-pid'));
32: 			}
33: 
34: 			$(window).off('action:ajaxify.end', onAjaxifyEnd)
35: 				.on('action:ajaxify.end', onAjaxifyEnd);
36: 
37: 			moveCommit.on('click', function () {
38: 				const targetTid = getTargetTid();
39: 				if (!targetTid) {
40: 					return;
41: 				}
42: 				moveCommit.attr('disabled', true);
43: 				const data = {
44: 					pids: postSelect.pids.slice(),
45: 					tid: targetTid,
46: 				};
47: 				if (config.undoTimeout > 0) {
48: 					return alerts.alert({
49: 						alert_id: 'pids_move_' + postSelect.pids.join('-'),
50: 						title: '[[topic:thread-tools.move-posts]]',
51: 						message: '[[topic:topic-move-posts-success]]',
52: 						type: 'success',
53: 						timeout: config.undoTimeout,
54: 						timeoutfn: function () {
55: 							movePosts(data);
56: 						},
57: 						clickfn: function (alert, params) {
58: 							delete params.timeoutfn;
59: 							alerts.success('[[topic:topic-move-posts-undone]]');
60: 							moveCommit.removeAttr('disabled');
61: 						},
62: 					});
63: 				}
64: 
65: 				movePosts(data);
66: 			});
67: 		});
68: 	};
69: 
70: 	function onAjaxifyEnd() {
71: 		if (!moveModal) {
72: 			return;
73: 		}
74: 		const tidInput = moveModal.find('#topicId');
75: 		let targetTid = null;
76: 		if (ajaxify.data.template.topic && ajaxify.data.tid &&
77: 			parseInt(ajaxify.data.tid, 10) !== fromTid
78: 		) {
79: 			targetTid = ajaxify.data.tid;
80: 		}
81: 		if (targetTid) {
82: 			tidInput.val(targetTid);
83: 		}
84: 		checkMoveButtonEnable();
85: 	}
86: 
87: 	function getTargetTid() {
88: 		const tidInput = moveModal.find('#topicId');
89: 		if (tidInput.length && tidInput.val()) {
90: 			return tidInput.val();
91: 		}
92: 		return ajaxify.data.template.topic && ajaxify.data.tid;
93: 	}
94: 
95: 	function showPostsSelected() {
96: 		if (!moveModal) {
97: 			return;
98: 		}
99: 		const targetTid = getTargetTid();
100: 		if (postSelect.pids.length) {
101: 			if (targetTid && parseInt(targetTid, 10) !== parseInt(fromTid, 10)) {
102: 				api.get('/topics/' + targetTid, {}).then(function (data) {
103: 					if (!data || !data.tid) {
104: 						return alerts.error('[[error:no-topic]]');
105: 					}
106: 					if (data.scheduled) {
107: 						return alerts.error('[[error:cant-move-posts-to-scheduled]]');
108: 					}
109: 					const translateStr = translator.compile('topic:x-posts-will-be-moved-to-y', postSelect.pids.length, data.title);
110: 					moveModal.find('#pids').translateHtml(translateStr);
111: 				});
112: 			} else {
113: 				moveModal.find('#pids').translateHtml('[[topic:x-posts-selected, ' + postSelect.pids.length + ']]');
114: 			}
115: 		} else {
116: 			moveModal.find('#pids').translateHtml('[[topic:no-posts-selected]]');
117: 		}
118: 	}
119: 
120: 	function checkMoveButtonEnable() {
121: 		if (!moveModal) {
122: 			return;
123: 		}
124: 		const targetTid = getTargetTid();
125: 		if (postSelect.pids.length && targetTid &&
126: 			parseInt(targetTid, 10) !== parseInt(fromTid, 10)
127: 		) {
128: 			moveCommit.removeAttr('disabled');
129: 		} else {
130: 			moveCommit.attr('disabled', true);
131: 		}
132: 		showPostsSelected();
133: 	}
134: 
135: 	function onPostToggled() {
136: 		checkMoveButtonEnable();
137: 	}
138: 
139: 	function movePosts(data) {
140: 		if (!data.tid) {
141: 			return;
142: 		}
143: 
144: 		Promise.all(data.pids.map(pid => api.put(`/posts/${encodeURIComponent(pid)}/move`, {
145: 			tid: data.tid,
146: 		}))).then(() => {
147: 			data.pids.forEach(function (pid) {
148: 				components.get('post', 'pid', pid).fadeOut(500, function () {
149: 					$(this).remove();
150: 				});
151: 			});
152: 			if (data.pids.length && ajaxify.data.template.topic &&
153: 				parseInt(data.tid, 10) === parseInt(ajaxify.data.tid, 10)) {
154: 				ajaxify.go(`/post/${data.pids[0]}`);
155: 			}
156: 			closeMoveModal();
157: 		}).catch(alerts.error);
158: 	}
159: 
160: 	function closeMoveModal() {
161: 		if (moveModal) {
162: 			moveModal.remove();
163: 			moveModal = null;
164: 			postSelect.disable();
165: 			$(window).off('action:ajaxify.end', onAjaxifyEnd);
166: 		}
167: 	}
168: 
169: 	return MovePost;
170: });
