39: 					loadList(val, function (categories) {
40: 						categoriesList = options.cacheList && (categoriesList || categories);
41: 						renderList(categories);
42: 					});
43: 				} else if (!val && categoriesList) {
44: 					renderList(categoriesList);
45: 				}
