73: 			api.get('/search/categories', {
74: 				search: search,
75: 				query: utils.params(),
76: 				parentCid: options.parentCid || 0,
77: 				selectedCids: options.selectedCids,
78: 				privilege: options.privilege,
79: 				states: options.states,
80: 				showLinks: options.showLinks,
81: 			}, function (err, { categories }) {
